function solve(nums, queries) {
    const MOD = 10**9 + 7;
    const n = nums.length;
    const product = new Array(n).fill(1);

    for (const [li, ri, ki, vi] of queries) {
        let idx = li;
        while (idx <= ri) {
            product[idx] = (product[idx] * vi) % MOD;
            idx += ki;
        }
    }

    let xor = 0;
    for (let i = 0; i < n; i++) {
        const val = (nums[i] * product[i]) % MOD;
        xor ^= val;
    }

    return xor;
}

