public static long solve(long[] nums, long[][] queries) {
    final long MOD = 1000000007L;
    int n = nums.length;
    long[] product = new long[n];
    for (int i = 0; i < n; i++) {
        product[i] = 1;
    }

    for (long[] query : queries) {
        int li = (int) query[0];
        int ri = (int) query[1];
        int ki = (int) query[2];
        long vi = query[3];
        int idx = li;
        while (idx <= ri) {
            product[idx] = (product[idx] * vi) % MOD;
            idx += ki;
        }
    }

    long xor = 0;
    for (int i = 0; i < n; i++) {
        long val = (nums[i] * product[i]) % MOD;
        xor ^= val;
    }

    return xor;
}
```

